/**
 * Fallback module declarations so the project type-checks before the native
 * dependencies are installed. After you run `yarn install` (and `pod install`)
 * on your Mac the packages ship their own richer types, which take precedence.
 * These bare declarations are harmless to keep, but can be deleted once installed.
 */
declare module 'lucide-react-native';
declare module 'react-native-toast-message';
declare module 'react-native-bootsplash';
